+            // New key: only INSERT trigger fires
+            "DELETE FROM kv_log; INSERT OR REPLACE INTO kv VALUES('d', 4); SELECT * FROM kv_log ORDER BY rowid",
+            // Final state
+            "SELECT * FROM kv ORDER BY k",
